+        const code = source.substring(start, i + 1).trim();
+        if (code.length > 0) {
+          statements.push({ code, start, end: i + 1 });
+        }
+        start = i + 1;
+        i++;
+        continue;
+      }
+
+      i++;
+      continue;
+    }
+
+    // ── Semicolon at depth 0 is a statement boundary ──
+    if (ch === ';' && depth === 0) {
+      const code = source.substring(start, i + 1).trim();
+      if (code.length > 0) {
+        statements.push({ code, start, end: i + 1 });
+      }
+      start = i + 1;
+      i++;
+      continue;
+    }
+
+    i++;
